const router = express.Router();
const supabase = require('../supabase');

// ONE-TIME seed route for financial module data
// Call: GET /api/fin-seed?secret=INTERLAND2026
// REMOVE THIS FILE AFTER SEEDING IS COMPLETE

const SECRET = 'INTERLAND2026';

async function upsertBatch(table, rows, conflictCol) {
  const results = { inserted: 0, errors: [] };
  const CHUNK = 50;
  for (let i = 0; i < rows.length; i += CHUNK) {
    const chunk = rows.slice(i, i + CHUNK);
    const { error } = await supabase
      .from(table)
      .upsert(chunk, { onConflict: conflictCol, ignoreDuplicates: true });
    if (error) results.errors.push(`${table} chunk ${i}: ${error.message}`);
    else results.inserted += chunk.length;
  }
  return results;
}

